"use client"
import { useState } from "react"
import { supabase } from "../../lib/supabase"

export default function CheckResultPage() {
  const [reg, setReg] = useState("")
  const [pin, setPin] = useState("")
  const [result, setResult] = useState<any>(null)
  const [error, setError] = useState("")
  const [loading, setLoading] = useState(false)

  const check = async () => {
    if (!reg || !pin) {
      setError("Please enter both Registration Number and PIN")
      return
    }

    setLoading(true)
    setError("")
    setResult(null)
    
    try {
      // 1. Validate PIN
      const { data: pinData, error: pinErr } = await supabase
        .from("result_pins")
        .select("student_id, is_used")
        .eq("pin", pin.toUpperCase())
        .single()
        
      if (pinErr || !pinData || pinData.is_used) {
        setError("❌ Invalid or used PIN. Please check and try again.")
        setLoading(false)
        return
      }

      // 2. Fetch student
      const { data: student, error: stuErr } = await supabase
        .from("students")
        .select("*, classes(name, level)")
        .eq("reg_number", reg.toUpperCase())
        .single()
        
      if (stuErr || !student) {
        setError("❌ Student not found. Check Registration Number.")
        setLoading(false)
        return
      }

      // 3. Fetch scores
      const { data: scores } = await supabase
        .from("scores")
        .select("score, assessments(type, name)")
        .eq("student_id", student.id)
        
      setResult({ student, scores })
      
      // Mark PIN used
      await supabase.from("result_pins").update({ is_used: true }).eq("id", pinData.id)
    } catch (err) {
      setError("❌ Network error. Please try again.")
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 via-indigo-50 to-purple-50 py-8 px-4">
      {/* Header */}
      <div className="max-w-2xl mx-auto mb-8 text-center">
        <div className="inline-flex items-center justify-center w-16 h-16 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-2xl shadow-lg mb-4">
          <svg className="w-8 h-8 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
          </svg>
        </div>
        <h1 className="text-3xl font-bold text-gray-900 mb-2">Check Your Result</h1>
        <p className="text-gray-600">Enter your details to view your term performance</p>
      </div>

      {/* Main Card */}
      <div className="max-w-2xl mx-auto">
        <div className="bg-white rounded-2xl shadow-xl overflow-hidden">
          {/* Card Header */}
          <div className="bg-gradient-to-r from-blue-600 to-indigo-600 px-6 py-4">
            <h2 className="text-xl font-semibold text-white">📚 Student Portal</h2>
          </div>

          <div className="p-6">
            {/* Input Fields */}
            <div className="space-y-4 mb-6">
              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Registration Number
                </label>
                <input
                  type="text"
                  placeholder="e.g., SS1/001"
                  value={reg}
                  onChange={(e) => setReg(e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all text-gray-900 placeholder-gray-400"
                />
              </div>

              <div>
                <label className="block text-sm font-medium text-gray-700 mb-2">
                  Result Checker PIN
                </label>
                <input
                  type="password"
                  placeholder="Enter your scratch card PIN"
                  value={pin}
                  onChange={(e) => setPin(e.target.value)}
                  className="w-full px-4 py-3 border border-gray-300 rounded-xl focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all text-gray-900 placeholder-gray-400"
                />
              </div>

              {/* Error Message */}
              {error && (
                <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded-lg">
                  <p className="text-red-700 text-sm">{error}</p>
                </div>
              )}

              {/* Check Button */}
              <button
                onClick={check}
                disabled={loading}
                className="w-full bg-gradient-to-r from-blue-600 to-indigo-600 hover:from-blue-700 hover:to-indigo-700 text-white font-semibold py-3 px-6 rounded-xl shadow-lg transform transition-all duration-200 hover:scale-[1.02] disabled:opacity-50 disabled:cursor-not-allowed disabled:transform-none"
              >
                {loading ? (
                  <span className="flex items-center justify-center">
                    <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                    </svg>
                    Checking Result...
                  </span>
                ) : (
                  "🔍 Check Result"
                )}
              </button>
            </div>

            {/* Result Display */}
            {result && (
              <div className="border-t border-gray-200 pt-6 mt-6">
                <div className="bg-gradient-to-r from-green-50 to-emerald-50 rounded-xl p-6 border border-green-200">
                  <div className="flex items-center mb-4">
                    <div className="w-12 h-12 bg-green-500 rounded-full flex items-center justify-center mr-4">
                      <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                      </svg>
                    </div>
                    <div>
                      <h3 className="text-lg font-bold text-gray-900">
                        {result.student.first_name} {result.student.last_name}
                      </h3>
                      <p className="text-sm text-gray-600">{result.student.reg_number}</p>
                    </div>
                  </div>

                  <div className="grid grid-cols-2 gap-4 mb-4">
                    <div className="bg-white rounded-lg p-3 shadow-sm">
                      <p className="text-xs text-gray-500 mb-1">Class</p>
                      <p className="font-semibold text-gray-900">{result.student.classes?.name || "N/A"}</p>
                    </div>
                    <div className="bg-white rounded-lg p-3 shadow-sm">
                      <p className="text-xs text-gray-500 mb-1">Level</p>
                      <p className="font-semibold text-gray-900">{result.student.classes?.level || "N/A"}</p>
                    </div>
                  </div>

                  <div className="bg-white rounded-lg p-4 shadow-sm">
                    <p className="text-sm text-gray-600 mb-2">📊 Total Scores Recorded</p>
                    <p className="text-3xl font-bold text-blue-600">{result.scores?.length || 0}</p>
                    <p className="text-xs text-gray-500 mt-1">subjects this term</p>
                  </div>

                  {result.scores && result.scores.length > 0 && (
                    <div className="mt-4">
                      <p className="text-sm font-medium text-gray-700 mb-2">📝 Subjects:</p>
                      <div className="space-y-2">
                        {result.scores.map((score: any, idx: number) => (
                          <div key={idx} className="flex justify-between items-center bg-white rounded-lg p-3">
                            <span className="text-sm font-medium text-gray-900">{score.assessments?.name || "Assessment"}</span>
                            <span className="text-lg font-bold text-blue-600">{score.score}/100</span>
                          </div>
                        ))}
                      </div>
                    </div>
                  )}
                </div>

                {/* Print/Share Button */}
                <button
                  onClick={() => window.print()}
                  className="w-full mt-4 bg-gray-100 hover:bg-gray-200 text-gray-700 font-semibold py-3 px-6 rounded-xl transition-colors duration-200"
                >
                  🖨️ Print Result
                </button>
              </div>
            )}
          </div>
        </div>

        {/* Footer */}
        <div className="text-center mt-6 text-gray-500 text-sm">
          <p>🔒 Secure Result Portal • PIN is single-use</p>
        </div>
      </div>
    </div>
  )
}